1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
6	<title>Stockio Dashboard</title>
7	<script src="https://cdn.jsdelivr.net/npm/chart.js@4"></script>
8	<style>
9	  :root {
10	    --bg: #0f0f23;
11	    --card: #1a1a3e;
12	    --card-border: #2a2a5e;
13	    --text: #e0e0e0;
14	    --text-dim: #8888aa;
15	    --accent: #4fc3f7;
16	    --green: #4caf50;
17	    --red: #ef5350;
18	    --hold: #9e9e9e;
19	    --font: system-ui, -apple-system, sans-serif;
20	    --mono: 'JetBrains Mono', 'Fira Code', monospace;
21	  }
22	  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
23	  body { background: var(--bg); color: var(--text); font-family: var(--font); line-height: 1.5; padding: 0; }
24	  a { color: var(--accent); text-decoration: none; }
25	
26	  /* Header */
27	  .header {
28	    display: flex; align-items: center; gap: 16px; padding: 12px 24px;
29	    background: #12122a; border-bottom: 1px solid var(--card-border); flex-wrap: wrap;
30	  }
31	  .header-title { font-size: 1.4rem; font-weight: 700; color: #fff; }
32	  .version-badge {
33	    font-size: 0.7rem; background: var(--accent); color: #000; padding: 2px 8px;
34	    border-radius: 10px; font-weight: 600; vertical-align: middle;
35	  }
36	  .header-spacer { flex: 1; }
37	  .instance-toggle { display: flex; gap: 0; }
38	  .instance-btn {
39	    padding: 6px 18px; border: 1px solid var(--card-border); background: var(--card);
40	    color: var(--text-dim); cursor: pointer; font-size: 0.85rem; font-family: var(--font);
41	    transition: all 0.15s;
42	  }
43	  .instance-btn:first-child { border-radius: 6px 0 0 6px; }
44	  .instance-btn:last-child { border-radius: 0 6px 6px 0; }
45	  .instance-btn.active { background: var(--accent); color: #000; font-weight: 600; border-color: var(--accent); }
46	  .ctrl-btn {
47	    padding: 6px 16px; border: 1px solid var(--card-border); border-radius: 6px;
48	    background: var(--card); color: var(--text); cursor: pointer; font-size: 0.85rem;
49	    font-family: var(--font); transition: all 0.15s;
50	  }
51	  .ctrl-btn:hover { border-color: var(--accent); }
52	  .ctrl-btn.running { border-color: var(--red); color: var(--red); }
53	  .ctrl-btn.stopped { border-color: var(--green); color: var(--green); }
54	  .status-dot {
55	    width: 10px; height: 10px; border-radius: 50%; display: inline-block;
56	  }
57	  .status-dot.running { background: var(--green); box-shadow: 0 0 6px var(--green); }
58	  .status-dot.stopped { background: var(--red); }
59	  .status-dot.halted { background: #ff9800; box-shadow: 0 0 6px #ff9800; }
60	  .status-label { font-size: 0.85rem; color: var(--text-dim); margin-left: 4px; }
61	  .market-status {
62	    font-size: 0.75rem; padding: 3px 10px; border-radius: 10px;
63	    font-weight: 600; margin-left: 8px;
64	  }
65	  .market-status.open { background: rgba(76,175,80,0.2); color: var(--green); }
66	  .market-status.closed { background: rgba(239,83,80,0.2); color: var(--red); }
67	  .header-meta { display: flex; align-items: center; gap: 12px; font-size: 0.75rem; color: var(--text-dim); }
68	  .next-cycle { font-family: var(--mono); }
69	  .last-updated { font-family: var(--mono); opacity: 0.7; }
70	  .gear-btn {
71	    background: none; border: none; color: var(--text-dim); cursor: pointer;
72	    font-size: 1.3rem; padding: 4px 8px; transition: color 0.15s;
73	  }
74	  .gear-btn:hover { color: var(--accent); }
75	
76	  /* Main layout */
77	  .main { max-width: 1400px; margin: 0 auto; padding: 20px 24px; }
78	
79	  /* Cards row */
80	  .cards { display: grid; grid-template-columns: repeat(4, 1fr); gap: 16px; margin-bottom: 20px; }
81	  .card {
82	    background: var(--card); border: 1px solid var(--card-border); border-radius: 10px;
83	    padding: 18px 20px;
84	  }
85	  .card-label { font-size: 0.78rem; color: var(--text-dim); text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 4px; }
86	  .card-label[data-tip] { cursor: help; border-bottom: 1px dotted var(--text-dim); }
87	  .card-sub { font-size: 0.75rem; color: var(--text-dim); font-family: var(--mono); margin-top: 2px; }
88	  .card-sub.positive { color: var(--green); }
89	  .card-sub.negative { color: var(--red); }
90	  .card-value { font-size: 1.6rem; font-weight: 700; font-family: var(--mono); }
91	  /* Margin bar */
92	  .margin-bar-track { height: 6px; background: #1e1e40; border-radius: 3px; margin-top: 6px; overflow: hidden; }
93	  .margin-bar-fill { height: 100%; border-radius: 3px; transition: width 0.3s; }
94	  /* Tooltips */
95	  [data-tip] { position: relative; }
96	  [data-tip]:hover::after {
97	    content: attr(data-tip); position: absolute; bottom: 100%; left: 50%;
98	    transform: translateX(-50%); padding: 6px 10px; background: #222244;
99	    border: 1px solid var(--card-border); border-radius: 6px; font-size: 0.72rem;
100	    color: var(--text); white-space: normal; width: max-content; max-width: 240px;
101	    z-index: 100; pointer-events: none; font-weight: 400; text-transform: none;
102	    letter-spacing: normal; line-height: 1.4; margin-bottom: 4px;
103	  }
104	  .card-value.positive { color: var(--green); }
105	  .card-value.negative { color: var(--red); }
106	
107	  /* Panels */
108	  .panel {
109	    background: var(--card); border: 1px solid var(--card-border); border-radius: 10px;
110	    padding: 18px 20px; margin-bottom: 20px;
111	  }
112	  .panel-title { font-size: 1rem; font-weight: 600; margin-bottom: 12px; color: #fff; }
113	
114	  /* Tables */
115	  .table-wrap { overflow-x: auto; }
116	  table { width: 100%; border-collapse: collapse; font-size: 0.82rem; }
117	  th { text-align: left; color: var(--text-dim); font-weight: 500; padding: 8px 10px;
118	       border-bottom: 1px solid var(--card-border); white-space: nowrap; font-size: 0.75rem;
119	       text-transform: uppercase; letter-spacing: 0.5px; }
120	  td { padding: 7px 10px; border-bottom: 1px solid #1e1e40; white-space: nowrap; font-family: var(--mono); font-size: 0.8rem; }
121	  tr:hover td { background: rgba(79, 195, 247, 0.04); }
122	  .dir-buy { color: var(--green); font-weight: 600; }
123	  .dir-sell { color: var(--red); font-weight: 600; }
124	  .dir-hold { color: var(--hold); }
125	  .scrollable-table { max-height: 340px; overflow-y: auto; }
126	
127	  /* Chart */
128	  .chart-container { position: relative; height: 280px; }
129	
130	  /* Bot log */
131	  .log-entry {
132	    border: 1px solid var(--card-border); border-radius: 8px; margin-bottom: 8px;
133	    overflow: hidden;
134	  }
135	  .log-header {
136	    display: flex; justify-content: space-between; align-items: center;
137	    padding: 10px 14px; cursor: pointer; background: rgba(255,255,255,0.02);
138	    transition: background 0.15s;
139	  }
140	  .log-header:hover { background: rgba(79, 195, 247, 0.05); }
141	  .log-cycle { font-weight: 600; font-family: var(--mono); font-size: 0.85rem; }
142	  .log-time { font-size: 0.75rem; color: var(--text-dim); }
143	  .log-arrow { color: var(--text-dim); transition: transform 0.2s; font-size: 0.8rem; }
144	  .log-arrow.open { transform: rotate(90deg); }
145	  .log-body { padding: 0 14px 12px; display: none; font-size: 0.82rem; }
146	  .log-body.open { display: block; }
147	  .log-stat { display: inline-block; margin-right: 18px; margin-top: 4px; }
148	  .log-stat-label { color: var(--text-dim); font-size: 0.75rem; }
149	  .log-stat-value { font-family: var(--mono); font-weight: 600; }
150	
151	  /* Engine footer */
152	  .engine-footer {
153	    display: flex; flex-wrap: wrap; gap: 24px; align-items: center;
154	    padding: 14px 20px; background: var(--card); border: 1px solid var(--card-border);
155	    border-radius: 10px; margin-bottom: 20px; font-size: 0.82rem;
156	  }
157	  .engine-stat-label { color: var(--text-dim); font-size: 0.72rem; text-transform: uppercase; }
158	  .engine-stat-value { font-family: var(--mono); font-weight: 600; }
159	  .halted-warning { color: #ff9800; font-weight: 600; }
160	
161	  /* Settings modal */
162	  .modal-overlay {
163	    display: none; position: fixed; inset: 0; background: rgba(0,0,0,0.7);
164	    z-index: 1000; justify-content: center; align-items: center;
165	  }
166	  .modal-overlay.open { display: flex; }
167	  .modal {
168	    background: var(--card); border: 1px solid var(--card-border); border-radius: 12px;
169	    padding: 24px 28px; width: 460px; max-width: 95vw; max-height: 90vh; overflow-y: auto;
170	  }
171	  .modal-title { font-size: 1.1rem; font-weight: 700; color: #fff; margin-bottom: 18px; }
172	  .form-group { margin-bottom: 14px; }
173	  .form-label { display: block; font-size: 0.78rem; color: var(--text-dim); margin-bottom: 4px; text-transform: uppercase; letter-spacing: 0.3px; }
174	  .form-input {
175	    width: 100%; padding: 8px 12px; background: var(--bg); border: 1px solid var(--card-border);
176	    border-radius: 6px; color: var(--text); font-family: var(--mono); font-size: 0.85rem;
177	  }
178	  .form-input:focus { outline: none; border-color: var(--accent); }
179	  .modal-actions { display: flex; justify-content: flex-end; gap: 10px; margin-top: 20px; }
180	  .btn-save {
181	    padding: 8px 20px; background: var(--accent); color: #000; border: none;
182	    border-radius: 6px; cursor: pointer; font-weight: 600; font-family: var(--font); font-size: 0.85rem;
183	  }
184	  .btn-cancel {
185	    padding: 8px 20px; background: transparent; color: var(--text-dim); border: 1px solid var(--card-border);
186	    border-radius: 6px; cursor: pointer; font-family: var(--font); font-size: 0.85rem;
187	  }
188	  .btn-save:hover { filter: brightness(1.1); }
189	  .btn-cancel:hover { border-color: var(--text-dim); }
190	
191	  .no-data { color: var(--text-dim); font-style: italic; padding: 16px 0; font-size: 0.85rem; }
192	
193	  /* Bot Summary */
194	  .panel.summary-panel {
195	    border-left: 3px solid var(--accent);
196	    background: linear-gradient(135deg, var(--card) 0%, rgba(79,195,247,0.06) 100%);
197	  }
198	  .panel.summary-panel .summary-text {
199	    font-size: 1rem; line-height: 1.6; color: var(--text);
200	  }

200	  }
201	
202	  /* Collapsible panels */
203	  .panel.collapsible .panel-title {
204	    cursor: pointer; user-select: none; display: flex; align-items: center; gap: 8px;
205	  }
206	  .panel.collapsible .panel-title .collapse-arrow {
207	    display: inline-block; font-size: 0.7rem; color: var(--text-dim);
208	    transition: transform 0.2s; flex-shrink: 0;
209	  }
210	  .panel.collapsible .panel-body { display: none; }
211	  .panel.collapsible.open .panel-body { display: block; }
212	  .panel.collapsible.open .panel-title .collapse-arrow { transform: rotate(90deg); }
213	
214	  /* Alert banner */
215	  #alertBanner {
216	    position: fixed; top: 0; left: 0; right: 0; z-index: 2000;
217	    padding: 12px 24px; font-size: 0.9rem; font-weight: 600;
218	    text-align: center; transform: translateY(-100%);
219	    transition: transform 0.35s ease; font-family: var(--font);
220	  }
221	  #alertBanner.visible { transform: translateY(0); }
222	  #alertBanner.trade { background: var(--green); color: #000; }
223	  #alertBanner.halted { background: #ff9800; color: #000; }
224	
225	  /* Responsive */
226	  @media (max-width: 900px) {
227	    .cards { grid-template-columns: repeat(2, 1fr); }
228	  }
229	  @media (max-width: 500px) {
230	    .cards { grid-template-columns: 1fr; }
231	    .header { padding: 10px 14px; gap: 10px; }
232	    .main { padding: 14px; }
233	  }
234	
235	  /* Scrollbar */
236	  ::-webkit-scrollbar { width: 6px; height: 6px; }
237	  ::-webkit-scrollbar-track { background: var(--bg); }
238	  ::-webkit-scrollbar-thumb { background: var(--card-border); border-radius: 3px; }
239	
240	  /* Sentiment combined scores */
241	  .sentiment-scores { display: flex; flex-wrap: wrap; gap: 10px; margin-top: 12px; }
242	  .sentiment-chip { background: var(--bg); border: 1px solid var(--card-border); border-radius: 6px; padding: 6px 12px; font-family: var(--mono); font-size: 0.8rem; }
243	
244	  /* Trump headlines */
245	  .trump-badge { display: inline-block; background: #ff9800; color: #000; font-size: 0.7rem; font-weight: 700; padding: 2px 8px; border-radius: 10px; margin-left: 8px; vertical-align: middle; }
246	  .headline-list { display: flex; flex-direction: column; gap: 8px; }
247	  .headline-pill { background: var(--bg); border: 1px solid var(--card-border); border-radius: 8px; padding: 10px 14px; font-size: 0.82rem; line-height: 1.4; }
248	  .headline-time { font-size: 0.72rem; color: var(--text-dim); margin-top: 10px; }
249	
250	  /* Indicator gauges */
251	  .indicator-grid { display: flex; flex-direction: column; gap: 14px; }
252	  .indicator-row { display: flex; align-items: center; gap: 14px; flex-wrap: wrap; }
253	  .indicator-row-label { min-width: 110px; font-family: var(--mono); font-size: 0.8rem; font-weight: 600; color: #fff; flex-shrink: 0; }
254	  .gauge-group { display: flex; gap: 14px; flex-wrap: wrap; flex: 1; }
255	  .mini-gauge { display: flex; flex-direction: column; align-items: center; min-width: 90px; }
256	  .mini-gauge-label { font-size: 0.68rem; color: var(--text-dim); text-transform: uppercase; margin-bottom: 3px; }
257	  .gauge-bar { width: 80px; height: 8px; background: #1e1e40; border-radius: 4px; overflow: hidden; position: relative; }
258	  .gauge-fill { height: 100%; border-radius: 4px; transition: width 0.3s; }
259	  .gauge-value { font-family: var(--mono); font-size: 0.72rem; margin-top: 2px; }
260	  .gauge-bar-bipolar { width: 80px; height: 8px; background: #1e1e40; border-radius: 4px; position: relative; overflow: hidden; }
261	  .gauge-bar-bipolar .gauge-center { position: absolute; left: 50%; top: 0; width: 1px; height: 100%; background: var(--text-dim); }
262	  .gauge-bar-bipolar .gauge-fill-bi { position: absolute; top: 0; height: 100%; border-radius: 4px; transition: width 0.3s, left 0.3s; }
263	
264	  /* Decision waterfall */
265	  .waterfall-list { display: flex; flex-direction: column; gap: 6px; }
266	  .waterfall-item { border: 1px solid var(--card-border); border-radius: 8px; overflow: hidden; }
267	  .waterfall-header { display: flex; justify-content: space-between; align-items: center; padding: 8px 14px; cursor: pointer; background: rgba(255,255,255,0.02); transition: background 0.15s; }
268	  .waterfall-header:hover { background: rgba(79,195,247,0.05); }
269	  .waterfall-label { font-family: var(--mono); font-size: 0.85rem; font-weight: 600; }
270	  .waterfall-summary { display: flex; align-items: center; gap: 10px; font-size: 0.8rem; }
271	  .waterfall-arrow { color: var(--text-dim); transition: transform 0.2s; font-size: 0.8rem; }
272	  .waterfall-arrow.open { transform: rotate(90deg); }
273	  .waterfall-body { display: none; padding: 8px 14px 12px; }
274	  .waterfall-body.open { display: block; }
275	  .waterfall-bar-track { width: 100%; height: 20px; background: #1e1e40; border-radius: 4px; position: relative; overflow: hidden; display: flex; margin-bottom: 6px; }
276	  .waterfall-seg { height: 100%; display: flex; align-items: center; justify-content: center; font-size: 0.65rem; font-family: var(--mono); color: #fff; min-width: 2px; overflow: hidden; white-space: nowrap; }
277	  .waterfall-detail-row { display: flex; justify-content: space-between; font-size: 0.78rem; padding: 2px 0; border-bottom: 1px solid #1e1e40; }
278	  .waterfall-detail-row:last-child { border-bottom: none; }
279	
280	  /* Model learning */
281	  .model-layout { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }
282	  .model-stats { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
283	  .model-stat-card { background: var(--bg); border: 1px solid var(--card-border); border-radius: 8px; padding: 12px; }
284	  .model-stat-card .card-label { font-size: 0.72rem; color: var(--text-dim); text-transform: uppercase; margin-bottom: 2px; }
285	  .model-stat-card .card-value { font-size: 1.1rem; font-weight: 700; font-family: var(--mono); }
286	  .streak-grid { display: flex; flex-wrap: wrap; gap: 4px; margin-top: 8px; }
287	  .streak-dot { width: 14px; height: 14px; border-radius: 3px; }
288	  .streak-dot.win { background: var(--green); }
289	  .streak-dot.loss { background: var(--red); }
290	  .cv-chart-container { height: 120px; margin-top: 12px; }
291	  .degraded-badge { display: inline-block; background: var(--red); color: #fff; font-size: 0.7rem; font-weight: 700; padding: 2px 8px; border-radius: 10px; }
292	
293	  /* Trade outcomes */
294	  .outcomes-top { display: grid; grid-template-columns: 1fr 160px; gap: 20px; align-items: center; margin-bottom: 16px; }
295	  .outcomes-big-stats { display: flex; gap: 24px; flex-wrap: wrap; }
296	  .big-stat { text-align: center; }
297	  .big-stat-value { font-size: 1.8rem; font-weight: 700; font-family: var(--mono); }
298	  .big-stat-label { font-size: 0.72rem; color: var(--text-dim); text-transform: uppercase; }
299	  .donut-container { position: relative; width: 120px; height: 120px; }
300	  .direction-bars { display: flex; gap: 20px; margin: 12px 0; }
301	  .dir-bar-group { flex: 1; }
302	  .dir-bar-label { font-size: 0.75rem; color: var(--text-dim); margin-bottom: 4px; }
303	  .dir-bar-track { height: 10px; background: #1e1e40; border-radius: 5px; overflow: hidden; }
304	  .dir-bar-fill { height: 100%; border-radius: 5px; transition: width 0.3s; }
305	  .recent-outcomes { display: flex; gap: 8px; flex-wrap: wrap; margin-top: 10px; }
306	  .outcome-item { display: flex; align-items: center; gap: 4px; background: var(--bg); border: 1px solid var(--card-border); border-radius: 6px; padding: 4px 10px; font-size: 0.75rem; font-family: var(--mono); }
307	  .outcome-icon { font-size: 0.9rem; }
308	  .outcome-icon.win { color: var(--green); }
309	  .outcome-icon.loss { color: var(--red); }
310	
311	  @media (max-width: 900px) {
312	    .model-layout { grid-template-columns: 1fr; }
313	    .outcomes-top { grid-template-columns: 1fr; }
314	  }
315	</style>
316	</head>
317	<body>
318	
319	<!-- Alert Banner -->
320	<div id="alertBanner"></div>
321	
322	<!-- Header -->
323	<div class="header">
324	  <span class="header-title">Stockio <span class="version-badge">{{ version|default('v0.1') }}</span></span>
325	  <div class="header-spacer"></div>
326	  <div class="instance-toggle">
327	    <button class="instance-btn active" data-instance="paper" onclick="switchInstance('paper')">Paper</button>
328	    <button class="instance-btn" data-instance="live" onclick="switchInstance('live')">Live</button>
329	  </div>
330	  <button id="startStopBtn" class="ctrl-btn stopped" onclick="toggleInstance()">Start</button>
331	  <span id="statusDot" class="status-dot stopped"></span>
332	  <span id="statusLabel" class="status-label">Stopped</span>
333	  <span id="marketStatus" class="market-status closed">Market Closed</span>
334	  <div class="header-meta">
335	    <span class="next-cycle" id="nextCycleLabel"></span>
336	    <span class="last-updated" id="lastUpdatedLabel"></span>
337	  </div>
338	  <button class="gear-btn" onclick="openSettings()" title="Settings">&#9881;</button>
339	</div>
340	
341	<!-- Main -->
342	<div class="main">
343	
344	  <!-- Portfolio Cards -->
345	  <div class="cards">
346	    <div class="card">
347	      <div class="card-label" data-tip="Cash in your account, excluding any unrealized profit or loss from open trades">Balance</div>
348	      <div class="card-value" id="cardBalance">--</div>
349	      <div class="card-sub" id="cardReturnPct"></div>
350	    </div>
351	    <div class="card">
352	      <div class="card-label" data-tip="Balance + unrealized P&L. This is what your account is actually worth right now">Equity</div>
353	      <div class="card-value" id="cardEquity">--</div>
354	    </div>
355	    <div class="card">
356	      <div class="card-label" data-tip="Profit or loss on trades that are still open. Becomes realized when you close the trade">Unrealized P&amp;L</div>
357	      <div class="card-value" id="cardPnl">--</div>
358	    </div>
359	    <div class="card">
360	      <div class="card-label" data-tip="Number of trades currently open. The bot limits this based on Max Positions in settings">Open Positions</div>
361	      <div class="card-value" id="cardPositions">--</div>
362	      <div class="card-sub" id="cardMarginLabel"></div>
363	      <div class="margin-bar-track" id="marginBarTrack" style="display:none">
364	        <div class="margin-bar-fill" id="marginBarFill"></div>
365	      </div>
366	    </div>
367	  </div>
368	
369	  <!-- Bot Summary -->
370	  <div class="panel summary-panel">
371	    <div class="panel-title">Bot Summary</div>
372	    <div class="summary-text" id="botSummary">Loading...</div>
373	  </div>
374	
375	  <!-- P&L Chart -->
376	  <div class="panel">
