521	async function fetchJSON(path) {
522	  try {
523	    const r = await fetch(api(path));
524	    if (!r.ok) throw new Error(r.status);
525	    return await r.json();
526	  } catch (e) {
527	    console.warn('Fetch failed:', path, e);
528	    return null;
529	  }
