532	function fmt(n, decimals) {
533	  if (n == null || isNaN(n)) return '--';
534	  decimals = decimals != null ? decimals : 2;
535	  return Number(n).toLocaleString(undefined, { minimumFractionDigits: decimals, maximumFractionDigits: decimals });
536	}
537	
538	function pnlClass(v) {
539	  if (v > 0) return 'positive';
540	  if (v < 0) return 'negative';
541	  return '';
542	}
543	
544	function dirClass(d) {
545	  if (!d) return '';
546	  const u = d.toUpperCase();
547	  if (u === 'BUY' || u === 'LONG') return 'dir-buy';
548	  if (u === 'SELL' || u === 'SHORT') return 'dir-sell';
549	  return 'dir-hold';
550	}
551	
552	function escHtml(s) {
553	  if (s == null) return '';
554	  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
555	}
