557	function shortTime(ts) {
558	  if (!ts) return '--';
559	  try {
560	    const d = new Date(ts);
561	    return d.toLocaleString(undefined, { month:'short', day:'numeric', hour:'2-digit', minute:'2-digit', second:'2-digit' });
562	  } catch { return ts; }
563	}
