720	async function refreshSignals() {
721	  const wrap = document.getElementById('signalsWrap');
722	  const [signals, sentiment] = await Promise.all([
723	    fetchJSON('/api/signals'),
724	    fetchJSON('/api/sentiment'),
725	  ]);
726	  if (!signals || !signals.length) {
727	    wrap.innerHTML = '<p class="no-data">No signals available</p>';
728	    _lastSignals = [];
729	    return;
730	  }
731	  _lastSignals = signals;
732	  const sentMap = (sentiment && sentiment.combined) ? sentiment.combined : (sentiment || {});
733	
734	  // Separate HOLD from actionable signals
735	  const actionable = signals.filter(s => s.direction && s.direction.toUpperCase() !== 'HOLD');
736	  const holdCount = signals.length - actionable.length;
737	
738	  // Sort by confidence descending
739	  actionable.sort((a, b) => (b.confidence || 0) - (a.confidence || 0));
740	
741	  if (!actionable.length) {
742	    wrap.innerHTML = '<p class="no-data">No actionable signals</p>'
743	      + (holdCount ? '<p style="font-size:0.78rem;color:var(--text-dim);margin-top:6px">' + holdCount + ' instrument' + (holdCount !== 1 ? 's' : '') + ' on HOLD (hidden)</p>' : '');
744	    return;
745	  }
746	
747	  let html = '<table><thead><tr>'
748	    + '<th>Instrument</th>'
749	    + '<th>Direction</th>'
750	    + '<th data-tip="How sure the bot is about this signal. Higher = stronger conviction">Confidence</th>'
751	    + '<th data-tip="News sentiment score. Positive = bullish news, negative = bearish news">Sentiment</th>'
752	    + '<th data-tip="Relative Strength Index (0-100). Below 30 = oversold (buy signal), above 70 = overbought (sell signal)">RSI 14</th>'
753	    + '<th data-tip="Moving Average Convergence Divergence. Positive = upward momentum, negative = downward momentum">MACD</th>'
754	    + '<th data-tip="Average Directional Index. Above 25 = strong trend, below 20 = weak/no trend">ADX</th>'
755	    + '</tr></thead><tbody>';
756	  actionable.forEach(s => {
757	    const sent = sentMap[s.instrument] != null ? sentMap[s.instrument] : s.sentiment;
758	    const sentColor = sent > 0 ? 'color:var(--green)' : (sent < 0 ? 'color:var(--red)' : '');
759	    html += '<tr>'
760	      + '<td>' + escHtml(s.instrument) + '</td>'
761	      + '<td class="' + dirClass(s.direction) + '">' + escHtml(s.direction) + '</td>'
762	      + '<td>' + (s.confidence != null ? (s.confidence * 100).toFixed(1) + '%' : '--') + '</td>'
763	      + '<td style="' + sentColor + '">' + (sent != null ? Number(sent).toFixed(2) : '--') + '</td>'
764	      + '<td>' + (s.rsi_14 != null ? Number(s.rsi_14).toFixed(1) : '--') + '</td>'
765	      + '<td>' + (s.macd != null ? Number(s.macd).toFixed(4) : '--') + '</td>'
766	      + '<td>' + (s.adx != null ? Number(s.adx).toFixed(1) : '--') + '</td>'
767	      + '</tr>';
768	  });
769	  html += '</tbody></table>';
770	  if (holdCount) {
771	    html += '<p style="font-size:0.78rem;color:var(--text-dim);margin-top:8px">' + holdCount + ' instrument' + (holdCount !== 1 ? 's' : '') + ' on HOLD (hidden)</p>';
772	  }
773	  wrap.innerHTML = html;
774	}
