795	      : '<span style="color:var(--accent)">OPEN</span>';
796	    html += '<tr>'
797	      + '<td>' + shortTime(t.timestamp) + '</td>'
798	      + '<td>' + escHtml(t.instrument) + '</td>'
799	      + '<td class="' + dirClass(t.direction) + '">' + escHtml(t.direction) + '</td>'
800	      + '<td>' + (t.units != null ? fmt(t.units, 0) : '--') + '</td>'
801	      + '<td>' + (t.price != null ? fmt(t.price, 5) : '--') + '</td>'
802	      + '<td>' + (t.exit_price != null ? fmt(t.exit_price, 5) : '--') + '</td>'
803	      + '<td style="' + pnlColor + ';font-family:var(--mono)">' + (pnl != null ? (pnl >= 0 ? '+' : '') + fmt(pnl, 4) : '--') + '</td>'
804	      + '<td>' + statusText + '</td>'
805	      + '<td>' + (t.confidence != null ? (t.confidence * 100).toFixed(1) + '%' : '--') + '</td>'
806	      + '</tr>';
807	  });
808	  html += '</tbody></table>';
809	  if (closedCount > 0) {
810	    const c = totalPnl >= 0 ? 'color:var(--green)' : 'color:var(--red)';
811	    html += '<div style="margin-top:10px;font-family:var(--mono);font-size:0.85rem;">'
812	      + 'Realized P&amp;L from ' + closedCount + ' closed trades: '
813	      + '<span style="' + c + ';font-weight:600">'
814	      + (totalPnl >= 0 ? '+' : '') + totalPnl.toFixed(4) + '</span></div>';
815	  }
816	  wrap.innerHTML = html;
817	}
