979	
980	  function bar(val, min, max, color) {
981	    const pct = Math.max(0, Math.min(100, ((val - min) / (max - min)) * 100));
982	    return '<div class="gauge-bar"><div class="gauge-fill" style="width:' + pct.toFixed(1) + '%;background:' + color + '"></div></div>';
983	  }
984	  function bipolar(val, absMax, posColor, negColor) {
985	    const clamped = Math.max(-absMax, Math.min(absMax, val));
