987	    const left = clamped >= 0 ? 50 : 50 - pct;
988	    const color = clamped >= 0 ? posColor : negColor;
989	    return '<div class="gauge-bar-bipolar"><div class="gauge-center"></div><div class="gauge-fill-bi" style="left:' + left.toFixed(1) + '%;width:' + pct.toFixed(1) + '%;background:' + color + '"></div></div>';
