1004	      + '<div class="mini-gauge"><span class="mini-gauge-label" data-tip="Bollinger Band position. Below 0.2 = near lower band (oversold), above 0.8 = near upper band (overbought)">BB %B</span>' + bar((d.bb_percent_b || 0.5) * 100, 0, 100, bbColor) + '<span class="gauge-value">' + (d.bb_percent_b != null ? d.bb_percent_b.toFixed(2) : '--') + '</span></div>'
