1208	
1209	  const actionable = signals.filter(s => s.direction && s.direction.toUpperCase() !== 'HOLD');
1210	  const totalInstruments = signals.length;
1211	  const cycles = eng ? (eng.cycle_count || 0) : 0;
1212	  const tradeCount = _lastTrade ? 'at least 1' : '0';
1213	
1214	  if (actionable.length > 0) {
1215	    actionable.sort((a, b) => (b.confidence || 0) - (a.confidence || 0));
1216	    const top = actionable[0];
1217	    const confPct = top.confidence != null ? (top.confidence * 100).toFixed(1) + '%' : '?';
1218	    el.textContent = 'Watching ' + actionable.length + ' potential trade' + (actionable.length !== 1 ? 's' : '')
1219	      + '. Strongest: ' + (top.instrument || '?') + ' ' + (top.direction || '?') + ' at ' + confPct + ' confidence. '
1220	      + cycles + ' cycle' + (cycles !== 1 ? 's' : '') + ' completed.';
1221	  } else {
1222	    el.textContent = 'Analyzing ' + totalInstruments + ' instrument' + (totalInstruments !== 1 ? 's' : '')
1223	      + '. No actionable signals this cycle.';
1224	  }
1225	}
1226	
1227	/* ── Alert Banner ── */
1228	function refreshAlertBanner() {
1229	  const banner = document.getElementById('alertBanner');
1230	  const eng = _lastEngineStatus;
1231	
1232	  // Check for halt
1233	  if (eng && eng.halted) {
1234	    showBanner('\u26A0 Trading halted: ' + (eng.halt_reason || 'Circuit breaker triggered'), 'halted');
1235	    return;
1236	  }
1237	
1238	  // Check for recent trade (within 60 seconds)
1239	  if (_lastTrade && _lastTrade.timestamp) {
1240	    const tradeTime = new Date(_lastTrade.timestamp).getTime();
1241	    const now = Date.now();
1242	    const tradeId = _lastTrade.trade_id || _lastTrade.id || _lastTrade.timestamp;
1243	    if ((now - tradeTime) < 60000 && tradeId !== _lastAlertTradeId) {
1244	      _lastAlertTradeId = tradeId;
1245	      const t = _lastTrade;
1246	      const msg = '\u2713 Trade executed: ' + (t.direction || '') + ' ' + (t.instrument || '') + ' '
1247	        + (t.units != null ? fmt(t.units, 0) + ' units' : '') + (t.price != null ? ' at ' + fmt(t.price, 5) : '');
1248	      showBanner(msg, 'trade');
1249	      return;
1250	    }
1251	  }
1252	}
1253	
1254	function showBanner(text, type) {
1255	  const banner = document.getElementById('alertBanner');
1256	  banner.textContent = text;
1257	  banner.className = type + ' visible';
1258	  if (_alertTimeout) clearTimeout(_alertTimeout);
1259	  _alertTimeout = setTimeout(() => {
1260	    banner.classList.remove('visible');
1261	  }, 30000);
1262	}
1263	
1264	/* ── Market hours ── */
1265	function isForexOpen() {
1266	  const now = new Date();
1267	  const day = now.getUTCDay();   // 0=Sun, 6=Sat
1268	  const hour = now.getUTCHours();
1269	  // Forex: Sunday 22:00 UTC → Friday 22:00 UTC
1270	  if (day === 0 && hour < 22) return false;   // Sunday before open
1271	  if (day === 6) return false;                 // Saturday
1272	  if (day === 5 && hour >= 22) return false;   // Friday after close
1273	  return true;
1274	}
1275	
1276	function refreshMarketStatus() {
1277	  const el = document.getElementById('marketStatus');
1278	  const open = isForexOpen();
1279	  el.textContent = open ? 'Market Open' : 'Market Closed';
1280	  el.className = 'market-status ' + (open ? 'open' : 'closed');
1281	}
1282	
1283	function refreshLastUpdated() {
1284	  const el = document.getElementById('lastUpdatedLabel');
1285	  if (!_lastRefreshTime) { el.textContent = ''; return; }
1286	  const ago = Math.round((Date.now() - _lastRefreshTime.getTime()) / 1000);
1287	  el.textContent = 'Updated ' + ago + 's ago';
1288	}
1289	
1290	function refreshNextCycle() {
1291	  const el = document.getElementById('nextCycleLabel');
1292	  if (!_lastCycleTime || !_cycleSeconds) { el.textContent = ''; return; }
1293	  const nextTime = _lastCycleTime.getTime() + _cycleSeconds * 1000;
1294	  const remaining = Math.max(0, Math.round((nextTime - Date.now()) / 1000));
1295	  if (remaining <= 0) { el.textContent = 'Cycle due...'; return; }
1296	  const m = Math.floor(remaining / 60);
1297	  const s = remaining % 60;
1298	  el.textContent = 'Next cycle ' + m + 'm ' + (s < 10 ? '0' : '') + s + 's';
1299	}
1300	
1301	// Tick the countdown and last-updated every second
1302	setInterval(() => { refreshLastUpdated(); refreshNextCycle(); }, 1000);
